// Parse Claude response and build freight record
const claudeResponse = JSON.parse($input.first().json.content[0].text);

// Generate unique quote ID
const quoteId = 'FQ-' + Date.now();
const intakeTime = new Date().toISOString();

// Customer carrier preference rules
// In production, fetch from database/Google Sheet
const carrierRules = {
  'default': ['Amazon Freight', 'UPS Freight', 'FedEx Freight', 'XPO Logistics', 'Old Dominion', 'Estes Express'],
  'customer_a@example.com': ['Amazon Freight'],
  'customer_b@example.com': ['UPS Freight', 'FedEx Freight']
};

// Customer markup rules
const markupRules = {
  'default': 0.15,
  'customer_a@example.com': 0.05,
  'customer_b@example.com': 0.12,
  'customer_c@example.com': 0.30
};

const customerEmail = claudeResponse.customer_email || $node['📧 Gmail Trigger — Inbound RFQ'].json.from;
const carriers = carrierRules[customerEmail] || carrierRules['default'];
const markupPct = markupRules[customerEmail] || markupRules['default'];

return [{
  json: {
    quote_id: quoteId,
    intake_time: intakeTime,
    status: 'INTAKE',
    customer_email: customerEmail,
    customer_name: claudeResponse.customer_name,
    origin: claudeResponse.origin,
    destination: claudeResponse.destination,
    weight_lbs: claudeResponse.weight_lbs,
    dimensions: claudeResponse.dimensions,
    freight_class: claudeResponse.freight_class,
    hazmat: claudeResponse.hazmat,
    accessorials: JSON.stringify(claudeResponse.accessorials || []),
    pickup_date: claudeResponse.required_pickup_date,
    special_notes: claudeResponse.special_notes,
    eligible_carriers: JSON.stringify(carriers),
    markup_pct: markupPct,
    timer_start: intakeTime,
    bid_deadline: new Date(Date.now() + 2 * 60 * 60 * 1000).toISOString(), // 2 hours
    rebid_deadline: null,
    winning_carrier: null,
    winning_rate: null,
    sell_rate: null,
    gross_profit: null,
    carriers_contacted: carriers.length,
    carriers_responded: 0,
    original_email_id: $node['📧 Gmail Trigger — Inbound RFQ'].json.id
  }
}];

// Split carriers into individual items for parallel email sending
const record = $input.first().json;
const carriers = JSON.parse(record.eligible_carriers);

const rfqTemplate = `Subject: Freight RFQ — ${record.quote_id}

Hello,

We have a freight shipment requiring immediate pricing. Please respond within 2 hours.

Quote Reference: ${record.quote_id}
Origin: ${record.origin}
Destination: ${record.destination}
Weight: ${record.weight_lbs} lbs
Dimensions: ${record.dimensions}
Freight Class: ${record.freight_class || 'TBD'}
Hazmat: ${record.hazmat ? 'YES — special handling required' : 'No'}
Accessorials: ${record.accessorials}
Required Pickup: ${record.pickup_date || 'ASAP'}

Please reply with:
1. Your best rate ($)
2. Transit time (days)
3. Any accessorial charges
4. Availability confirmation

Bid deadline: ${record.bid_deadline}
Include reference ${record.quote_id} in your reply subject line.

AMZ Prep Logistics`;

return carriers.map(carrier => ({
  json: {
    ...record,
    carrier_name: carrier,
    rfq_email_body: rfqTemplate
  }
}));

