// Check if all carriers responded or 2-hour timer expired
// In production: query Google Sheets for this quote_id
// For beta: simplified check based on response count

const quoteId = JSON.parse($input.first().json.content[0].text).quote_id;

// Simulate: in production fetch from Sheets
const carriersContacted = 6;
const carriersResponded = 4; // fetch real count from Sheets
const bidDeadline = new Date(Date.now() - 1000); // simulate expired for demo
const timerExpired = new Date() > bidDeadline;

const shouldTriggerRebid = timerExpired || (carriersResponded >= carriersContacted);

return [{ json: { should_trigger_rebid: shouldTriggerRebid, quote_id: quoteId } }];

// Find lowest rate from responses and build re-bid message
// In production: query Google Sheets Rate Responses tab

// Simulated rate comparison (replace with actual Sheets lookup)
const rates = [
  { carrier: 'Amazon Freight', rate: 950 },
  { carrier: 'UPS Freight', rate: 1100 },
  { carrier: 'FedEx Freight', rate: 875 },
  { carrier: 'XPO Logistics', rate: 990 }
];

const winner = rates.reduce((min, r) => r.rate < min.rate ? r : min);
const losers = rates.filter(r => r.carrier !== winner.carrier);

const rebidMessage = `Re-Bid Request — Final Round

Thank you for your quote on ${$json.quote_id}.

We have received a competitive rate of $${winner.rate} for this shipment.

This is your opportunity to submit a final best rate.

Deadline: 30 minutes from receipt of this email.

Please reply with your absolute best rate.
Include ${$json.quote_id} in your subject line.

AMZ Prep Logistics`;

return losers.map(carrier => ({
  json: {
    quote_id: $json.quote_id,
    carrier_name: carrier.carrier,
    current_lowest: winner.rate,
    winning_carrier_temp: winner.carrier,
    rebid_message: rebidMessage,
    rebid_deadline: new Date(Date.now() + 30 * 60 * 1000).toISOString()
  }
}));

// After re-bid window closes — select final winner
// Apply customer markup — calculate sell rate and margin

// Simulated final rates (replace with Sheets lookup)
const finalRates = [
  { carrier: 'FedEx Freight', rate: 875 }, // original winner
  { carrier: 'Amazon Freight', rate: 820 }, // re-bid came in lower
  { carrier: 'XPO Logistics', rate: 900 }
];

const winner = finalRates.reduce((min, r) => r.rate < min.rate ? r : min);

// Customer markup (fetched from freight record)
const markupPct = 0.15; // 15% default — replace with actual from record
const sellRate = Math.ceil(winner.rate * (1 + markupPct));
const grossProfit = sellRate - winner.rate;
const grossProfitPct = ((grossProfit / sellRate) * 100).toFixed(1);

return [{
  json: {
    quote_id: $json.quote_id,
    winning_carrier: winner.carrier,
    carrier_rate: winner.rate,
    markup_pct: markupPct,
    sell_rate: sellRate,
    gross_profit_usd: grossProfit,
    gross_profit_pct: parseFloat(grossProfitPct),
    quote_expiry: new Date(Date.now() + 4 * 60 * 60 * 1000).toISOString()
  }
}];

